/* ==UserStyle==
@name           matugen global styles
@namespace      github.com/openstyles/stylus
@version        1.0.0
@description    mine, not yours
@author         bhimio
==/UserStyle== */

:root {
    /* Primary Colors */
    --primary: #B4C7ED;
    --on-primary: #2E4060;
    --primary-container: #405373;
    --on-primary-container: #D7E3FF;
    --inverse-primary: #4D5F81;
    --primary-fixed: #C2D5FC;
    --primary-fixed-dim: #B4C7ED;
    --on-primary-fixed: #243655;
    --on-primary-fixed-variant: #415373;

    /* Secondary Colors */
    --secondary: #BEC7DC;
    --on-secondary: #374052;
    --secondary-container: #333C4D;
    --on-secondary-container: #B6BFD5;
    --secondary-fixed: #DAE2F9;
    --secondary-fixed-dim: #CCD4EA;
    --on-secondary-fixed: #374051;
    --on-secondary-fixed-variant: #535C6E;

    /* Tertiary Colors */
    --tertiary: #EBDCFF;
    --on-tertiary: #594B74;
    --tertiary-container: #DFCCFD;
    --on-tertiary-container: #50426A;
    --tertiary-fixed: #DFCCFD;
    --tertiary-fixed-dim: #D1BEEF;
    --on-tertiary-fixed: #3D2F56;
    --on-tertiary-fixed-variant: #5A4B74;

    /* Surface & Background */
    --background: #0C0E12;
    --on-background: #E3E5EF;
    --surface: #0C0E12;
    --on-surface: #E3E5EF;
    --surface-variant: #22262D;
    --on-surface-variant: #A8ABB5;
    --surface-dim: #0C0E12;
    --surface-bright: #292C34;
    --surface-container-lowest: #000000;
    --surface-container-low: #111318;
    --surface-container: #171A1F;
    --surface-container-high: #1D2026;
    --surface-container-highest: #22262D;
    --inverse-surface: #F9F9FE;
    --inverse-on-surface: #545559;
    --surface-tint: #B4C7ED;

    /* Error Colors */
    --error: #FA746F;
    --on-error: #490006;
    --error-container: #871F21;
    --on-error-container: #FF9993;

    /* Outline & Misc */
    --outline: #72757E;
    --outline-variant: #444850;
    --shadow: #000000;
    --scrim: #000000;
}
